export const PostInvoicesInputSchema = z.object({
  account_tax_ids: z.unknown().describe("The account tax IDs associated with the invoice. Only editable when the invoice is a draft.").optional(),
  application_fee_amount: z.number().int().describe("A fee in cents (or local equivalent) that will be applied to the invoice and transferred to the application owner's Stripe account. The request must be made with an OAuth key or the Stripe-Account header in order to take an application fee. For more information, see the application fees [documentation](https://docs.stripe.com/billing/invoices/connect#collecting-fees).").optional(),
  auto_advance: z.boolean().describe("Controls whether Stripe performs [automatic collection](https://docs.stripe.com/invoicing/integration/automatic-advancement-collection) of the invoice. If `false`, the invoice's state doesn't automatically advance without an explicit action. Defaults to false.").optional(),
  automatic_tax: z.record(z.unknown()).describe("Settings for automatic tax lookup for this invoice.").optional(),
  automatically_finalizes_at: z.number().int().describe("The time when this invoice should be scheduled to finalize (up to 5 years in the future). The invoice is finalized at this time if it's still in draft state.").optional(),
  collection_method: z.enum(["charge_automatically","send_invoice"]).describe("Either `charge_automatically`, or `send_invoice`. When charging automatically, Stripe will attempt to pay this invoice using the default source attached to the customer. When sending an invoice, Stripe will email this invoice to the customer with payment instructions. Defaults to `charge_automatically`.").optional(),
  currency: z.string().describe("The currency to create this invoice in. Defaults to that of `customer` if not specified.").optional(),
  custom_fields: z.unknown().describe("A list of up to 4 custom fields to be displayed on the invoice.").optional(),
  customer: z.string().describe("The ID of the customer to bill.").optional(),
  customer_account: z.string().describe("The ID of the account to bill.").optional(),
  days_until_due: z.number().int().describe("The number of days from when the invoice is created until it is due. Valid only for invoices where `collection_method=send_invoice`.").optional(),
  default_payment_method: z.string().describe("ID of the default payment method for the invoice. It must belong to the customer associated with the invoice. If not set, defaults to the subscription's default payment method, if any, or to the default payment method in the customer's invoice settings.").optional(),
  default_source: z.string().describe("ID of the default payment source for the invoice. It must belong to the customer associated with the invoice and be in a chargeable state. If not set, defaults to the subscription's default source, if any, or to the customer's default source.").optional(),
  default_tax_rates: z.array(z.string()).describe("The tax rates that will apply to any line item that does not have `tax_rates` set.").optional(),
  description: z.string().describe("An arbitrary string attached to the object. Often useful for displaying to users. Referenced as 'memo' in the Dashboard.").optional(),
  discounts: z.unknown().describe("The coupons and promotion codes to redeem into discounts for the invoice. If not specified, inherits the discount from the invoice's customer. Pass an empty string to avoid inheriting any discounts.").optional(),
  due_date: z.number().int().describe("The date on which payment for this invoice is due. Valid only for invoices where `collection_method=send_invoice`.").optional(),
  effective_at: z.number().int().describe("The date when this invoice is in effect. Same as `finalized_at` unless overwritten. When defined, this value replaces the system-generated 'Date of issue' printed on the invoice PDF and receipt.").optional(),
  expand: z.array(z.string()).describe("Specifies which fields in the response should be expanded.").optional(),
  footer: z.string().describe("Footer to be displayed on the invoice.").optional(),
  from_invoice: z.record(z.unknown()).describe("Revise an existing invoice. The new invoice will be created in `status=draft`. See the [revision documentation](https://docs.stripe.com/invoicing/invoice-revisions) for more details.").optional(),
  issuer: z.record(z.unknown()).describe("The connected account that issues the invoice. The invoice is presented with the branding and support information of the specified account.").optional(),
  metadata: z.unknown().describe("Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format. Individual keys can be unset by posting an empty value to them. All keys can be unset by posting an empty value to `metadata`.").optional(),
  number: z.string().describe("Set the number for this invoice. If no number is present then a number will be assigned automatically when the invoice is finalized. In many markets, regulations require invoices to be unique, sequential and / or gapless. You are responsible for ensuring this is true across all your different invoicing systems in the event that you edit the invoice number using our API. If you use only Stripe for your invoices and do not change invoice numbers, Stripe handles this aspect of compliance for you automatically.").optional(),
  on_behalf_of: z.string().describe("The account (if any) for which the funds of the invoice payment are intended. If set, the invoice will be presented with the branding and support information of the specified account. See the [Invoices with Connect](https://docs.stripe.com/billing/invoices/connect) documentation for details.").optional(),
  payment_settings: z.record(z.unknown()).describe("Configuration settings for the PaymentIntent that is generated when the invoice is finalized.").optional(),
  pending_invoice_items_behavior: z.enum(["exclude","include"]).describe("How to handle pending invoice items on invoice creation. Defaults to `exclude` if the parameter is omitted.").optional(),
  rendering: z.record(z.unknown()).describe("The rendering-related settings that control how the invoice is displayed on customer-facing surfaces such as PDF and Hosted Invoice Page.").optional(),
  shipping_cost: z.record(z.unknown()).describe("Settings for the cost of shipping for this invoice.").optional(),
  shipping_details: z.record(z.unknown()).describe("Shipping details for the invoice. The Invoice PDF will use the `shipping_details` value if it is set, otherwise the PDF will render the shipping address from the customer.").optional(),
  statement_descriptor: z.string().describe("Extra information about a charge for the customer's credit card statement. It must contain at least one letter. If not specified and this invoice is part of a subscription, the default `statement_descriptor` will be set to the first subscription item's product's `statement_descriptor`.").optional(),
  subscription: z.string().describe("The ID of the subscription to invoice, if any. If set, the created invoice will only include pending invoice items for that subscription. The subscription's billing cycle and regular subscription events won't be affected.").optional(),
  transfer_data: z.record(z.unknown()).describe("If specified, the funds from the invoice will be transferred to the destination and the ID of the resulting transfer will be found on the invoice's charge.").optional(),
});

