export const PostPaymentLinksPaymentLinkInputSchema = z.object({
  payment_link: z.string(),
  active: z.boolean().describe("Whether the payment link's `url` is active. If `false`, customers visiting the URL will be shown a page saying that the link has been deactivated.").optional(),
  after_completion: z.record(z.unknown()).describe("Behavior after the purchase is complete.").optional(),
  allow_promotion_codes: z.boolean().describe("Enables user redeemable promotion codes.").optional(),
  automatic_tax: z.record(z.unknown()).describe("Configuration for automatic tax collection.").optional(),
  billing_address_collection: z.enum(["auto","required"]).describe("Configuration for collecting the customer's billing address. Defaults to `auto`.").optional(),
  custom_fields: z.unknown().describe("Collect additional information from your customer using custom fields. Up to 3 fields are supported. You can't set this parameter if `ui_mode` is `custom`.").optional(),
  custom_text: z.record(z.unknown()).describe("Display additional text for your customers using custom text. You can't set this parameter if `ui_mode` is `custom`.").optional(),
  customer_creation: z.enum(["always","if_required"]).describe("Configures whether [checkout sessions](https://docs.stripe.com/api/checkout/sessions) created by this payment link create a [Customer](https://docs.stripe.com/api/customers).").optional(),
  expand: z.array(z.string()).describe("Specifies which fields in the response should be expanded.").optional(),
  inactive_message: z.unknown().describe("The custom message to be displayed to a customer when a payment link is no longer active.").optional(),
  invoice_creation: z.record(z.unknown()).describe("Generate a post-purchase Invoice for one-time payments.").optional(),
  line_items: z.array(z.record(z.unknown())).describe("The line items representing what is being sold. Each line item represents an item being sold. Up to 20 line items are supported.").optional(),
  metadata: z.record(z.unknown()).describe("Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format. Individual keys can be unset by posting an empty value to them. All keys can be unset by posting an empty value to `metadata`. Metadata associated with this Payment Link will automatically be copied to [checkout sessions](https://docs.stripe.com/api/checkout/sessions) created by this payment link.").optional(),
  name_collection: z.unknown().describe("Controls settings applied for collecting the customer's name.").optional(),
  optional_items: z.unknown().describe("A list of optional items the customer can add to their order at checkout. Use this parameter to pass one-time or recurring [Prices](https://docs.stripe.com/api/prices).\nThere is a maximum of 10 optional items allowed on a payment link, and the existing limits on the number of line items allowed on a payment link apply to the combined number of line items and optional items.\nThere is a maximum of 20 combined line items and optional items.").optional(),
  payment_intent_data: z.record(z.unknown()).describe("A subset of parameters to be passed to PaymentIntent creation for Checkout Sessions in `payment` mode.").optional(),
  payment_method_collection: z.enum(["always","if_required"]).describe("Specify whether Checkout should collect a payment method. When set to `if_required`, Checkout will not collect a payment method when the total due for the session is 0.This may occur if the Checkout Session includes a free trial or a discount.\n\nCan only be set in `subscription` mode. Defaults to `always`.\n\nIf you'd like information on how to collect a payment method outside of Checkout, read the guide on [configuring subscriptions with a free trial](https://docs.stripe.com/payments/checkout/free-trials).").optional(),
  payment_method_options: z.unknown().describe("Payment-method-specific configuration.").optional(),
  payment_method_types: z.unknown().describe("The list of payment method types that customers can use. Pass an empty string to enable dynamic payment methods that use your [payment method settings](https://dashboard.stripe.com/settings/payment_methods).").optional(),
  phone_number_collection: z.record(z.unknown()).describe("Controls phone number collection settings during checkout.\n\nWe recommend that you review your privacy policy and check with your legal contacts.").optional(),
  restrictions: z.unknown().describe("Settings that restrict the usage of a payment link.").optional(),
  shipping_address_collection: z.unknown().describe("Configuration for collecting the customer's shipping address.").optional(),
  submit_type: z.enum(["auto","book","donate","pay","subscribe"]).describe("Describes the type of transaction being performed in order to customize relevant text on the page, such as the submit button. Changing this value will also affect the hostname in the [url](https://docs.stripe.com/api/payment_links/payment_links/object#url) property (example: `donate.stripe.com`).").optional(),
  subscription_data: z.record(z.unknown()).describe("When creating a subscription, the specified configuration data will be used. There must be at least one line item with a recurring price to use `subscription_data`.").optional(),
  tax_id_collection: z.record(z.unknown()).describe("Controls tax ID collection during checkout.").optional(),
});

