export const PostQuotesInputSchema = z.object({
  application_fee_amount: z.unknown().describe("The amount of the application fee (if any) that will be requested to be applied to the payment and transferred to the application owner's Stripe account. There cannot be any line items with recurring prices when using this field.").optional(),
  application_fee_percent: z.unknown().describe("A non-negative decimal between 0 and 100, with at most two decimal places. This represents the percentage of the subscription invoice total that will be transferred to the application owner's Stripe account. There must be at least 1 line item with a recurring price to use this field.").optional(),
  automatic_tax: z.record(z.unknown()).describe("Settings for automatic tax lookup for this quote and resulting invoices and subscriptions.").optional(),
  collection_method: z.enum(["charge_automatically","send_invoice"]).describe("Either `charge_automatically`, or `send_invoice`. When charging automatically, Stripe will attempt to pay invoices at the end of the subscription cycle or at invoice finalization using the default payment method attached to the subscription or customer. When sending an invoice, Stripe will email your customer an invoice with payment instructions and mark the subscription as `active`. Defaults to `charge_automatically`.").optional(),
  customer: z.string().describe("The customer for which this quote belongs to. A customer is required before finalizing the quote. Once specified, it cannot be changed.").optional(),
  customer_account: z.string().describe("The account for which this quote belongs to. A customer or account is required before finalizing the quote. Once specified, it cannot be changed.").optional(),
  default_tax_rates: z.unknown().describe("The tax rates that will apply to any line item that does not have `tax_rates` set.").optional(),
  description: z.unknown().describe("A description that will be displayed on the quote PDF. If no value is passed, the default description configured in your [quote template settings](https://dashboard.stripe.com/settings/billing/quote) will be used.").optional(),
  discounts: z.unknown().describe("The discounts applied to the quote.").optional(),
  expand: z.array(z.string()).describe("Specifies which fields in the response should be expanded.").optional(),
  expires_at: z.number().int().describe("A future timestamp on which the quote will be canceled if in `open` or `draft` status. Measured in seconds since the Unix epoch. If no value is passed, the default expiration date configured in your [quote template settings](https://dashboard.stripe.com/settings/billing/quote) will be used.").optional(),
  footer: z.unknown().describe("A footer that will be displayed on the quote PDF. If no value is passed, the default footer configured in your [quote template settings](https://dashboard.stripe.com/settings/billing/quote) will be used.").optional(),
  from_quote: z.record(z.unknown()).describe("Clone an existing quote. The new quote will be created in `status=draft`. When using this parameter, you cannot specify any other parameters except for `expires_at`.").optional(),
  header: z.unknown().describe("A header that will be displayed on the quote PDF. If no value is passed, the default header configured in your [quote template settings](https://dashboard.stripe.com/settings/billing/quote) will be used.").optional(),
  invoice_settings: z.record(z.unknown()).describe("All invoices will be billed using the specified settings.").optional(),
  line_items: z.array(z.record(z.unknown())).describe("A list of line items the customer is being quoted for. Each line item includes information about the product, the quantity, and the resulting cost.").optional(),
  metadata: z.record(z.unknown()).describe("Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format. Individual keys can be unset by posting an empty value to them. All keys can be unset by posting an empty value to `metadata`.").optional(),
  on_behalf_of: z.unknown().describe("The account on behalf of which to charge.").optional(),
  subscription_data: z.record(z.unknown()).describe("When creating a subscription or subscription schedule, the specified configuration data will be used. There must be at least one line item with a recurring price for a subscription or subscription schedule to be created. A subscription schedule is created if `subscription_data[effective_date]` is present and in the future, otherwise a subscription is created.").optional(),
  test_clock: z.string().describe("ID of the test clock to attach to the quote.").optional(),
  transfer_data: z.unknown().describe("The data with which to automatically create a Transfer for each of the invoices.").optional(),
});

